// RegisterConnectorServiceHandlerWithProvider registers handlers for the specified LLM provider
func RegisterConnectorServiceHandlerWithProvider(s *mcpserver.MCPServer, srv ConnectorServiceServer, provider runtime.LLMProvider, opts ...runtime.Option) {
	switch provider {
	case runtime.LLMProviderOpenAI:
		RegisterConnectorServiceHandlerOpenAI(s, srv, opts...)
	case runtime.LLMProviderStandard:
		fallthrough
	default:
		RegisterConnectorServiceHandler(s, srv, opts...)
	}
}

